questionvariables.text:
/* 1. Base Multiplier for Cone Proportions (3-4-5 ratio for clean slant height) */
multiplier: 1 + rand(3);     /* Generates 1, 2, or 3 */

/* 2. Dimensions */
r: 3 * multiplier;           /* Radius: 3, 6, or 9 m */
h_cone: 4 * multiplier;      /* Conical height: 4, 8, or 12 m */
h_cyl: 4 + rand(5);          /* Cylinder height: 4 to 8 m */

/* 3. Volume Calculations */
V_cyl: %pi * r^2 * h_cyl;
V_cone: (1/3) * %pi * r^2 * h_cone;

total_m3: V_cyl + V_cone;
total_litres: total_m3 * 1000;

/* Teacher Answer */
ta: total_litres;

/* 4. Display Variables for Feedback */
r2: r^2;
